import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import ScreenShell from '../components/ScreenShell';
import PrimaryButton from '../components/PrimaryButton';
import { COLORS } from '../styles/theme';

export default function IndexScreen({ navigation }) {
  return (
    <ScreenShell>
      <View style={styles.heroHeader}>
        <View style={styles.logoMark}>
          <Text style={styles.logoEmoji}>🐾</Text>
        </View>
        <Text style={styles.title}>Sano y Salvo</Text>
        <Text style={styles.subtitle}>Encuentra y reporta mascotas con una interfaz clara y simple.</Text>
      </View>

      <View style={styles.heroImageSpace}>
        <View style={styles.heroImagePlaceholder} />
      </View>

      <View style={styles.actions}>
        <PrimaryButton title="Registrarse" onPress={() => navigation.navigate('Register')} style={styles.button} />
        <PrimaryButton title="Login" variant="ghost" onPress={() => navigation.navigate('Login')} style={styles.button} />
      </View>
    </ScreenShell>
  );
}

const styles = StyleSheet.create({
  heroHeader: {
    marginTop: 36,
    marginBottom: 22,
    alignItems: 'center'
  },
  heroImageSpace: {
    marginTop: 8,
    marginBottom: 12,
    alignItems: 'center',
    justifyContent: 'center'
  },
  heroImagePlaceholder: {
    width: '100%',
    maxWidth: 420,
    height: 240,
    backgroundColor: 'transparent',
    borderWidth: 0,
    borderRadius: 28
  },
  actions: { marginTop: 24, gap: 12 },
  button: { width: '100%' },
  logoMark: {
    width: 76,
    height: 76,
    borderRadius: 24,
    backgroundColor: COLORS.soft,
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 14
  },
  logoEmoji: { fontSize: 34 },
  title: {
    fontSize: 34,
    fontWeight: '900',
    color: COLORS.text,
    textAlign: 'center'
  },
  subtitle: {
    marginTop: 10,
    color: COLORS.muted,
    textAlign: 'center',
    lineHeight: 22,
    maxWidth: 320
  }
});
